import { useState, useEffect, useCallback } from "react";
import axios from "axios";
import "./styles/global.css";

// Importações
import Navbar      from "./components/Navbar";
import FormPanel   from "./components/FormPanel";
import Toast       from "./components/Toast";
import Footer      from "./components/Footer";
import LandingPage from "./components/LandingPage";
import AdminDashboard from "./components/AdminDashboard";
import BarbeiroLogin from "./components/BarbeiroLogin"; 
import DeleteModal from "./components/DeleteModal";
import DynamicFavicon from "./components/DynamicFavicon"; 

const EMPTY_FORM = { name: '', service: '', date: '', time: '' };
const API_URL = "http://localhost:8080/agendamento";

export default function App() {
  const [view, setView] = useState("landing"); 
  const [isAuthenticated, setIsAuthenticated] = useState(false); 
  const [appointments, setAppointments] = useState([]); // Garantir que comece como array vazio
  const [form, setForm] = useState(EMPTY_FORM);
  const [editingId, setEditingId] = useState(null);
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [toast, setToast] = useState(null);

  const showToast = (msg, type = "success") => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  };

  const fetchAppointments = useCallback(async () => {
    try {
      const response = await axios.get(API_URL);
      // Trava de segurança: Se o back retornar erro ou algo que não seja array
      if (response.data && Array.isArray(response.data)) {
        const formattedData = response.data.map(item => ({
          id: item.id,
          name: item.clienteNome || "Cliente",
          service: item.servico || "Corte",
          date: item.dataHora ? item.dataHora.split('T')[0] : "",
          time: item.dataHora ? item.dataHora.split('T')[1].substring(0, 5) : "",
          status: item.confirmado ? "confirmado" : "pendente"
        }));
        setAppointments(formattedData);
      }
    } catch (error) {
      console.error("Back-end offline:", error.message);
      setAppointments([]); // Mantém o array vazio para o map() não quebrar
    }
  }, []);

  useEffect(() => {
    if (view === "admin" && isAuthenticated) fetchAppointments();
  }, [view, isAuthenticated, fetchAppointments]);

  // Renderização principal com tratamento de erro
  try {
    return (
      <>
        <DynamicFavicon />

        {view === "landing" && (
          <LandingPage onNavigate={(dest) => setView(dest)} />
        )}

        {view === "admin" && (
          !isAuthenticated ? (
            <BarbeiroLogin 
              onLogin={() => setIsAuthenticated(true)} 
              onGoHome={() => setView("landing")} 
            />
          ) : (
            <>
              <AdminDashboard 
                appointments={appointments || []} 
                onEdit={handleEdit}
                onDeleteRequest={setDeleteTarget}
                onLogout={() => { setIsAuthenticated(false); setView("landing"); }}
                editingId={editingId}
                form={form}
                setForm={setForm}
                onSubmit={() => {}} // Função vazia para teste
                onCancel={() => { setForm(EMPTY_FORM); setEditingId(null); }}
              />
              <DeleteModal target={deleteTarget} onConfirm={() => {}} onCancel={() => setDeleteTarget(null)} />
              <Toast toast={toast} />
            </>
          )
        )}

        {view === "schedule" && (
          <div style={{ background: '#000', minHeight: '100vh', color: '#fff' }}>
            <Navbar onGoHome={() => setView("landing")} />

            <main style={{ padding: '40px', textAlign: 'center' }}>
              {/* O FormPanel só carrega se o form existir */}
              {form && (
                <FormPanel 
                  form={form} 
                  setForm={setForm} 
                  editing={false} 
                  onSubmit={() => {}} 
                />
              )}

              <div style={{ marginTop: '50px' }}>
                <h2 style={{ fontSize: '40px', color: '#D4AF37' }}>Palheta Barbearia</h2>
                <p>O Back-end está desligado, mas a tela carregou!</p>
              </div>
            </main>

            <Footer onNavigate={(dest) => setView(dest)} />
            <Toast toast={toast} />
          </div>
        )}
      </>
    );
  } catch (err) {
    return <div style={{color: 'white', padding: '20px'}}>Erro Crítico: {err.message}</div>;
  }
}
